"use client";

import React, { useState } from 'react';
import { Calendar, Home, BookOpen, Star, FileText } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const TABS = [
  { id: 'hoy', name: 'Hoy', icon: Home },
  { id: 'semana', name: 'Semana', icon: Calendar },
  { id: 'habitos', name: 'Hábitos', icon: Star },
  { id: 'devocional', name: 'Devocional', icon: BookOpen },
  { id: 'notas', name: 'Notas', icon: FileText },
];

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (id: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  return (
    <div className="flex min-h-screen bg-cream-pastel overflow-hidden">
      {/* Sidebar - Desktop */}
      <aside 
        className={`hidden md:flex flex-col w-64 bg-white border-r border-rose-pastel journal-shadow transition-all duration-300 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}
      >
        <div className="p-6">
          <h1 className="text-2xl font-serif text-deep-rose italic font-semibold">Diario de Abigail</h1>
          <p className="text-xs text-soft-text mt-1 opacity-70">Cada día es una nueva oportunidad para crecer.</p>
        </div>
        
        <nav className="flex-1 px-4 py-6 space-y-2">
          {TABS.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
                activeTab === tab.id 
                  ? 'bg-rose-pastel text-deep-rose font-medium' 
                  : 'text-soft-text hover:bg-lavender-pastel'
              }`}
            >
              <tab.icon size={20} />
              <span>{tab.name}</span>
            </button>
          ))}
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-h-screen relative overflow-y-auto pb-20 md:pb-0">
        <header className="md:hidden p-4 bg-white border-b border-rose-pastel flex justify-between items-center sticky top-0 z-10">
          <div>
            <h1 className="text-xl font-serif text-deep-rose italic font-semibold">Diario de Abigail</h1>
          </div>
          <Star className="text-accent-pink" size={24} />
        </header>

        <div className="flex-1 p-4 md:p-8 max-w-5xl mx-auto w-full">
          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              transition={{ duration: 0.3 }}
            >
              {children}
            </motion.div>
          </AnimatePresence>
        </div>

        {/* Bottom Navigation - Mobile */}
        <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-rose-pastel flex justify-around p-2 journal-shadow z-20">
          {TABS.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex flex-col items-center p-2 rounded-lg ${
                activeTab === tab.id ? 'text-deep-rose' : 'text-soft-text opacity-50'
              }`}
            >
              <tab.icon size={22} />
              <span className="text-[10px] mt-1">{tab.name}</span>
            </button>
          ))}
        </nav>
      </main>
    </div>
  );
};

export default Layout;
