"use client";
import React, { useState } from 'react';
import { useJournal } from '../context/JournalContext';
import { CheckCircle2, Circle, Plus, Heart, Sparkles, NotepadText, Lightbulb } from 'lucide-react';

const MOODS = [
  { emoji: '😊', label: 'Feliz' },
  { emoji: '🌸', label: 'Tranquila' },
  { emoji: '✨', label: 'Inspirada' },
  { emoji: '☁️', label: 'Cansada' },
  { emoji: '💝', label: 'Amada' },
];

const Hoy: React.FC = () => {
  const { state, updateToday } = useJournal();
  const { today } = state;
  const [newTask, setNewTask] = useState('');

  const handlePriorityChange = (index: number, value: string) => {
    const newPriorities = [...today.priorities];
    newPriorities[index] = value;
    updateToday({ priorities: newPriorities });
  };

  const addTask = () => {
    if (!newTask.trim()) return;
    const task = { id: Date.now().toString(), text: newTask, completed: false };
    updateToday({ tasks: [...today.tasks, task] });
    setNewTask('');
  };

  const toggleTask = (id: string) => {
    updateToday({
      tasks: today.tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t)
    });
  };

  const handleGratitudeChange = (index: number, value: string) => {
    const newGratitude = [...today.gratitude];
    newGratitude[index] = value;
    updateToday({ gratitude: newGratitude });
  };

  return (
    <div className="space-y-6 max-w-2xl mx-auto pb-10">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-2 border-b border-rose-pastel pb-4">
        <div>
          <h2 className="text-3xl font-serif text-soft-text font-light italic">Hola, Abigail</h2>
          <p className="text-soft-text/60 font-medium">
            {new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
          </p>
        </div>
        <div className="flex gap-2 bg-white/50 p-2 rounded-2xl">
          {MOODS.map((m) => (
            <button
              key={m.label}
              onClick={() => updateToday({ mood: m.emoji })}
              className={`text-2xl p-2 rounded-xl transition-all ${today.mood === m.emoji ? 'bg-accent-pink scale-110' : 'hover:bg-rose-pastel'}`}
              title={m.label}
            >
              {m.emoji}
            </button>
          ))}
        </div>
      </header>

      {/* Prioridades */}
      <section className="bg-white p-6 rounded-3xl journal-shadow border border-rose-pastel/30">
        <div className="flex items-center gap-2 mb-4 text-deep-rose font-medium">
          <Sparkles size={20} />
          <h3>Prioridades del Día</h3>
        </div>
        <div className="space-y-3">
          {today.priorities.map((p, i) => (
            <div key={i} className="flex items-center gap-3">
              <span className="text-accent-pink font-serif italic">{i + 1}.</span>
              <input
                type="text"
                value={p}
                onChange={(e) => handlePriorityChange(i, e.target.value)}
                placeholder="Escribe algo importante..."
                className="flex-1 bg-transparent border-b border-rose-pastel/50 focus:border-accent-pink outline-none py-1 text-soft-text transition-colors"
              />
            </div>
          ))}
        </div>
      </section>

      {/* Tareas */}
      <section className="bg-white p-6 rounded-3xl journal-shadow border border-rose-pastel/30">
        <div className="flex items-center gap-2 mb-4 text-deep-rose font-medium">
          <CheckCircle2 size={20} />
          <h3>Lista de Tareas</h3>
        </div>
        <div className="space-y-3 mb-4">
          {today.tasks.map((task) => (
            <div key={task.id} className="flex items-center gap-3 group">
              <button onClick={() => toggleTask(task.id)} className="text-accent-pink transition-transform hover:scale-110">
                {task.completed ? <CheckCircle2 size={20} fill="#fbcfe8" /> : <Circle size={20} />}
              </button>
              <span className={`flex-1 ${task.completed ? 'line-through text-soft-text/40' : 'text-soft-text'}`}>
                {task.text}
              </span>
            </div>
          ))}
        </div>
        <div className="flex gap-2">
          <input
            type="text"
            value={newTask}
            onChange={(e) => setNewTask(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && addTask()}
            placeholder="Nueva tarea..."
            className="flex-1 bg-lavender-pastel/30 border border-rose-pastel/30 rounded-xl px-4 py-2 outline-none focus:border-accent-pink transition-all"
          />
          <button 
            onClick={addTask}
            className="bg-accent-pink text-white p-2 rounded-xl hover:bg-deep-rose/40 transition-colors"
          >
            <Plus size={24} />
          </button>
        </div>
      </section>

      {/* Recordatorios y Notas rápidas */}
      <div className="grid md:grid-cols-2 gap-6">
        <section className="bg-white p-6 rounded-3xl journal-shadow border border-rose-pastel/30">
          <div className="flex items-center gap-2 mb-3 text-deep-rose font-medium">
            <Lightbulb size={18} />
            <h3>Recordatorios</h3>
          </div>
          <textarea
            value={today.reminders}
            onChange={(e) => updateToday({ reminders: e.target.value })}
            placeholder="No olvides..."
            className="w-full h-24 bg-transparent border-none outline-none resize-none text-soft-text placeholder:italic"
          />
        </section>
        <section className="bg-white p-6 rounded-3xl journal-shadow border border-rose-pastel/30">
          <div className="flex items-center gap-2 mb-3 text-deep-rose font-medium">
            <NotepadText size={18} />
            <h3>Notas Rápidas</h3>
          </div>
          <textarea
            value={today.quickNotes}
            onChange={(e) => updateToday({ quickNotes: e.target.value })}
            placeholder="Ideas del momento..."
            className="w-full h-24 bg-transparent border-none outline-none resize-none text-soft-text placeholder:italic"
          />
        </section>
      </div>

      {/* Agradecimientos */}
      <section className="bg-rose-pastel/40 p-6 rounded-3xl border border-rose-pastel/60">
        <div className="flex items-center gap-2 mb-4 text-deep-rose font-medium">
          <Heart size={20} className="fill-accent-pink" />
          <h3>Hoy agradezco por...</h3>
        </div>
        <div className="space-y-3">
          {today.gratitude.map((g, i) => (
            <input
              key={i}
              type="text"
              value={g}
              onChange={(e) => handleGratitudeChange(i, e.target.value)}
              placeholder="Escribe un agradecimiento..."
              className="w-full bg-transparent border-b border-white/60 focus:border-accent-pink outline-none py-1 text-soft-text italic"
            />
          ))}
        </div>
      </section>
    </div>
  );
};

export default Hoy;
