"use client";
import React, { useState } from 'react';
import { useJournal } from '../context/JournalContext';
import { StickyNote, Plus, Trash2 } from 'lucide-react';

const Notas: React.FC = () => {
  const { state } = useJournal();
  const [notes, setNotes] = useState<string[]>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('diario_abigail_notes');
      return saved ? JSON.parse(saved) : [];
    }
    return [];
  });
  const [newNote, setNewNote] = useState('');

  const saveNotes = (updatedNotes: string[]) => {
    setNotes(updatedNotes);
    localStorage.setItem('diario_abigail_notes', JSON.stringify(updatedNotes));
  };

  const addNote = () => {
    if (newNote.trim()) {
      const updated = [newNote, ...notes];
      saveNotes(updated);
      setNewNote('');
    }
  };

  const deleteNote = (index: number) => {
    const updated = notes.filter((_, i) => i !== index);
    saveNotes(updated);
  };

  return (
    <div className="space-y-6 max-w-4xl mx-auto">
      <header className="border-b border-rose-pastel pb-4">
        <h2 className="text-3xl font-serif text-soft-text font-light italic">Mis Notas</h2>
        <p className="text-soft-text/60 font-medium">Captura tus pensamientos e ideas</p>
      </header>

      <div className="flex gap-3 bg-white p-4 rounded-3xl journal-shadow border border-rose-pastel/30">
        <textarea
          value={newNote}
          onChange={(e) => setNewNote(e.target.value)}
          placeholder="Escribe una nueva nota aquí..."
          className="flex-1 bg-transparent border-none outline-none text-soft-text px-2 resize-none h-24"
        />
        <button 
          onClick={addNote}
          className="bg-accent-pink text-white p-4 rounded-2xl hover:bg-deep-rose/40 transition-colors self-end"
        >
          <Plus size={24} />
        </button>
      </div>

      <div className="grid sm:grid-cols-2 gap-4">
        {notes.map((note, i) => (
          <div key={i} className="bg-white p-6 rounded-3xl journal-shadow border border-rose-pastel/20 relative group hover:border-accent-pink/40 transition-all">
            <button 
              onClick={() => deleteNote(i)}
              className="absolute top-4 right-4 text-soft-text/20 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
            >
              <Trash2 size={18} />
            </button>
            <div className="flex items-start gap-3">
              <StickyNote size={20} className="text-accent-pink shrink-0 mt-1" />
              <p className="text-soft-text whitespace-pre-wrap leading-relaxed">{note}</p>
            </div>
            <div className="mt-4 pt-4 border-t border-rose-pastel/10 flex justify-end">
              <span className="text-[10px] text-soft-text/30 font-medium uppercase tracking-widest">
                Nota Personal
              </span>
            </div>
          </div>
        ))}
      </div>
      
      {notes.length === 0 && (
        <div className="text-center py-20 opacity-30 italic font-serif">
          No hay notas aún... escribe tu primer pensamiento arriba.
        </div>
      )}
    </div>
  );
};

export default Notas;
